'First person' refers to user with ID 1;
'Second person' refers to user with ID 2;
'Top and bottom clothing items' are the product categories named 'TOP' and 'BOTTOM';
'Latest sizes' imply the most recently updated size codes;

sql:
SELECT COUNT(*) AS total_active_categories
FROM product_categories
WHERE is_active = 1;

SELECT AVG(us_size) AS average_us_size
FROM size_reference
WHERE product_category = 'TOP' AND is_active = 1;

SELECT AVG(uk_size) AS average_uk_size
FROM size_reference
WHERE product_category = 'TOP';

SELECT AVG(chest_cm) AS average_chest_cm
FROM size_reference
WHERE product_category = 'TOP' AND is_active = 1;

SELECT size_code
FROM size_reference
WHERE product_category = 'TOP' AND is_active = 1;

SELECT AVG(waist_cm) AS avg_waist_cm
FROM size_reference
WHERE product_category = 'TOP' AND size_code = 'M';

SELECT product_category, AVG(waist_cm) AS avg_waist_cm
FROM size_reference
GROUP BY product_category;

SELECT AVG(uk_size) AS average_uk_size
FROM size_reference
WHERE product_category = 'TOP' AND size_code = 'M';

SELECT AVG(shoulders_cm) AS average_shoulder_cm
FROM size_reference
WHERE is_active = 1;

SELECT AVG(shoulder_to_shoulder_cm) AS average_shoulder_to_shoulder_cm
FROM size_reference
WHERE product_category = 'BOTTOM';
